public static str getDimValue(LedgerDefaultDimensionValueSet ledgerDimensionAccount, Name dimName)
{
    DimensionAttributeLevelValueAllView  dimAttrView;
    DimensionAttribute dimAttr;
    str dimvalue;
    select DisplayValue from dimAttrView where dimattrview.ValueCombinationRecId == ledgerDimensionAccount
                  join BackingEntityType from dimAttr
                where dimAttr.RecId == dimAttrView.DimensionAttribute
            && dimAttr.Name == dimName;
    if(dimAttrView.DisplayValue)
    {
        dimvalue = dimAttrView.DisplayValue;
    }
    return dimvalue;
}

public static DimensionValue getDimensionDisplayValue(RecId _defaultDimension, Name _dimName)
{
    DimensionAttributeValueSetStorage dimStorage;

    dimStorage = DimensionAttributeValueSetStorage::find(_defaultDimension);

    return dimStorage.getDisplayValueByDimensionAttribute(DimensionAttribute::findByName(_dimName).RecId);
}
